import SwiftUI

enum SettingsSidebarIconKind {
    case home
    case custom
    case transcription
    case translation
    case rewrite
    case appEnhancement
    case note
    case dictionary
    case history
    case feedback
    case permissions
    case hotkey
    case settings
    case model
    case about
}

extension SettingsTab {
    var sidebarIconKind: SettingsSidebarIconKind {
        switch self {
        case .report:
            return .home
        case .feature, .appEnhancement:
            return .custom
        case .dictionary:
            return .dictionary
        case .history:
            return .history
        case .general:
            return .settings
        case .model:
            return .model
        case .permissions:
            return .permissions
        case .hotkey:
            return .hotkey
        case .about:
            return .about
        }
    }
}

extension FeatureSettingsTab {
    var sidebarIconKind: SettingsSidebarIconKind? {
        switch self {
        case .transcription:
            return .transcription
        case .translation:
            return .translation
        case .rewrite:
            return .rewrite
        case .appEnhancement:
            return .appEnhancement
        case .note:
            return .note
        }
    }
}

