            .fill(.primary)
    }

    private func strokePath(
        _ pathData: String,
        lineWidth: CGFloat = 1.5,
        viewport: CGSize = CGSize(width: 24, height: 24)
    ) -> some View {
        SVGPathShape(pathData: pathData, viewport: viewport)
            .stroke(
                .primary,
                style: StrokeStyle(lineWidth: lineWidth, lineCap: .round, lineJoin: .round)
            )
    }
